"""
mkt-original | Leviticus | 24-25
Script: zc-original-leviticus-24-25-fill.py
Run: python3 scripts/zc-original-leviticus-24-25-fill.py

Ch 24: Ner tamid (perpetual lamp), lechem ha-panim (bread of presence), blasphemer's execution, lex talionis
Ch 25: Shemittah (sabbatical year), Yovel/Jubilee (freedom/deror), land theology (ki li ha-aretz),
       go'el/geulah (kinsman-redeemer), prohibition on neshekh/tarbith (interest), ki avadai hem

Key Hebrew terms:
- ner tamid (H5216+H8548): perpetual lamp; tamid = continual/perpetual
- lechem ha-panim: bread of the face/presence; the twelve loaves before YHWH
- niqev shem (H5344): to blaspheme = to pierce/bore through the Name
- lex talionis: nefesh tachat nefesh, 'ayin tachat 'ayin — proportional justice
- shemittah (H8057): sabbatical year; from shamat = to release/drop
- yovel (H3104): jubilee = ram's horn; deror (H1865) = liberty
- go'el (H1350): kinsman-redeemer; geulah (H1353) = redemption
- neshekh (H5392): interest = to bite; tarbith (H8635) = increase/profit
- parekhk (H6531): crushing labor = the Egyptian slave-labor word
- ki li ha-aretz: the land is mine — YHWH's ownership claim undergirds jubilee
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists(): return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing: existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]: existing[ch][v] = html

LEVITICUS = {
    "24": {
        "1": "<p>The divine-speech formula <em>vayedabber YHWH el-Moshe lemor</em> introduces two distinct units: the lamp and bread instructions (vv. 2-9) and the blasphemer case (vv. 10-23). The juxtaposition is structural — the perpetual presence of light and bread in the sanctuary (the ongoing covenant relationship) is immediately followed by a case-law that tests the covenant's protection of the divine Name.</p>",
        "2": "<p><strong>Shemen zayit zakh katit</strong> (<em>zakh</em>, H2134; <em>katit</em>, H3795): 'pure pressed olive oil.' <em>Zakh</em> = clear, pure, unadulterated; <em>katit</em> = beaten/crushed in a mortar (not extracted by pressing the whole olive, but from olives beaten to release oil without bitter residue). <strong>Ner tamid</strong> (<em>tamid</em>, H8548): 'perpetual/continual lamp' — <em>tamid</em> means unbroken continuity, not necessarily a flame never extinguished but one always maintained in attendance. The same adjective qualifies the daily burnt offering (<em>'olat ha-tamid</em>) and the bread of presence — it marks the perpetual character of covenant worship.</p>",
        "3": "<p><strong>Lifne YHWH tamid</strong>: 'before YHWH continually.' Aaron tends the lamp from evening to morning — the light burns through the night (when natural light is absent) before YHWH. <strong>Chuqat 'olam</strong> (H2708+H5769): perpetual statute — the same formula used for the Sabbath (Ex 31:16) and the fat-prohibition (Lev 3:17). The lamp's maintenance is not merely practical (lighting the sanctuary) but relational — a covenant obligation to keep the light of YHWH's presence burning.</p>",
        "4": "<p><strong>Menorah ha-tahor</strong>: the pure (gold) lampstand. The lampstand's specification as 'pure' (<em>tahor</em>) refers to the refined gold of its construction (Ex 25:31). Aaron tends the lamps <em>lifne YHWH tamid</em> — the repeated phrase from v. 3 emphasizes that the lamp-tending is always <em>before YHWH</em>, not merely in the sacred space. The orientation of the priest's work is toward YHWH, not toward the congregation or any human audience.</p>",
        "5": "<p><strong>Solet</strong> (H5560) fine flour for the bread; <strong>shetim 'esronim</strong> (two-tenths of an ephah) per loaf — approximately 4.4 liters of flour each. The twelve loaves correspond to the twelve tribes: the bread represents the totality of Israel's covenant community before YHWH. <em>Challot</em> (H2471): loaves or flat-cakes. The specific quantity per loaf and the total of twelve encode the theological numerology of the covenant: completeness of the people before the complete God.</p>",
        "6": "<p><strong>Shisha ha-madreg</strong>: 'six in a row.' Two rows of six on the <strong>shulchan ha-tahor</strong> (the pure gold table, Ex 25:23-30). The table and bread together constitute the <em>lechem ha-panim</em> (H3899+H6440): 'bread of the face/presence' — bread that stands in the face-to-face space before YHWH. The term <em>panim</em> (face) echoes the promise of Presence in Ex 33:14-15 (<em>panai yelekhu</em> = 'my face will go'). The bread at YHWH's face is the covenant meal held in perpetuity.</p>",
        "7": "<p><strong>Levonah zakkah</strong> (H3828+H2134): pure frankincense — a costly aromatic resin. It is placed on each row as an <strong>'azkara</strong> (H234): memorial/representative portion. The frankincense is burned as the <em>reah nihoah</em> for YHWH; the bread itself is not burned but presented and then given to the priests (v. 9). The <em>'azkara</em> structure here (frankincense = the burned representative) means the bread-rows are acceptable to YHWH through the frankincense memorial even though the bread itself goes to the priests.</p>",
        "8": "<p><strong>Beyom ha-Shabbat</strong>: every Sabbath the bread is renewed — fresh loaves replace the previous week's. The renewal cycle on the Sabbath connects the bread of presence to the covenant's temporal rhythm: the bread is not a one-time offering but a perpetually renewed covenant act. <strong>Berit 'olam</strong> (H1285+H5769): 'covenant forever' — this specific phrase, linking the bread to the eternal covenant, elevates the showbread from a food-ritual to a covenant-sign. Compare Gen 9:16 (rainbow), 17:7 (circumcision), Ex 31:16 (Sabbath).</p>",
        "9": "<p><strong>Qodesh qodashim</strong>: 'most holy' — the bread, though not burned, carries the highest holiness grade when eaten by the priests. Aaron and his sons eat it <em>bimqom qadosh</em> (in a holy place). <strong>Me'ishei YHWH chok 'olam</strong>: from YHWH's food offerings, a perpetual portion. The priestly consumption of the bread of presence is the completion of the covenant meal: YHWH presents (the bread before his face), and the priests receive and eat. The meal is conducted between YHWH and his mediating household.</p>",
        "10": "<p><strong>Ben isha Israelit</strong> and <strong>ish Mitzri</strong> (Egyptian father): a man of mixed ancestry. This narrative interruption in the legal material highlights that the laws which follow apply across ethnic lines. The legal case emerges from a fight (<em>vayinnatzu</em>) in the camp — the blasphemy happened in a social conflict context, not in a cultic one. The blasphemer's identity (mixed heritage) sets up the ruling in v. 22 that the same law applies to the foreigner and the native-born.</p>",
        "11": "<p><strong>Vayiqov</strong> (<em>naqav</em>, H5344): the specific verb for blasphemy of the Name — 'to pierce, to bore through, to profane by explicit use.' <em>Naqav</em> differs from the more common <em>galah</em> (to uncover/profane) or <em>hillel</em> (to desecrate): it implies a direct, specific use of the Name in a degrading or magical-manipulative way. <strong>Wayyeqalel</strong> (<em>qalal</em>, H7043): 'to curse, to treat as light/contemptible' — the opposite of <em>kaved</em> (to honor/weigh heavily). The blasphemy is both specific name-use (<em>naqav</em>) and contemptuous devaluation (<em>qalal</em>).</p>",
        "12": "<p><strong>Lifros lahem al pi YHWH</strong>: 'until the matter was made clear to them through YHWH's mouth.' The custody pending divine ruling reflects the legal system's acknowledgment of a hard case: the community knows the act is serious but does not yet know the prescribed response for this specific crime. The consultation model — bringing exceptional cases to YHWH for ruling — parallels the daughters of Zelophehad (Num 27) and the Passover exception (Num 9).</p>",
        "13": "<p>Second divine-speech formula (<em>vayedabber YHWH</em>) within the chapter — signaling that the following ruling on blasphemy is a direct divine legal decision, not Moses's inference from existing law. The narrative structure (case → consultation → divine ruling → execution → legal principle → execution) is the standard form for <em>midrash</em>-type legal development in the Torah.</p>",
        "14": "<p>The execution procedure for blasphemy: <strong>vesamkhu khol ha-shom'im et yedeihem al rosho</strong> — 'all who heard lay their hands on his head.' The witnesses become the first executioners — the laying of hands by witnesses reverses the <em>semikhah</em> of sacrifice (where the offerer's hand identifies with the animal). Here the witnesses' hands transfer the guilt back to the blasphemer before the community executes judgment. <strong>Venirgemuhu</strong> (H7275, H7275): stoning by the whole congregation.</p>",
        "15": "<p><strong>Ish ish ki yeqalel Elohav venasa cheto</strong>: 'Any person who curses his God shall bear his guilt.' The formulation <em>'ish 'ish</em> ('any man, any man' — an emphatic repetition in Hebrew law) universalizes the principle to every person without exception. <strong>Venasa cheto</strong>: 'shall bear his guilt/sin' — the language of guilt-bearing used across Leviticus for violations that fall on the transgressor himself. The passive form emphasizes that the guilt does not disappear but remains attached to the person.</p>",
        "16": "<p><strong>Niqev shem YHWH mot yumat</strong>: 'Whoever pierces/blasphemes the name of YHWH shall be put to death.' The same <em>naqav</em> verb from v. 11. The death penalty applies to <strong>ger</strong> (resident alien) and <strong>ezrach</strong> (native-born) equally — the only verse in the Torah that explicitly applies the blasphemy law to non-Israelites. The equal application reflects the Name's absolute status: YHWH's name is not protected as Israel's tribal property but as the identity of the Creator God of all people.</p>",
        "17": "<p><strong>Ki yakkeh kol nefesh adam mot yumat</strong>: 'Whoever strikes down any human being (<em>nefesh adam</em>) shall be put to death.' <em>Nefesh</em> (H5315): life-self, person, soul — here in the compound <em>nefesh adam</em> emphasizing the full personhood of the one killed. The term <em>adam</em> (human being, from <em>adamah</em> = ground) makes the protection of human life universal: not 'any Israelite' but 'any human being.' The life-protection law is grounded in the image of God (<em>tselem Elohim</em>, Gen 9:6) in which all humanity shares.</p>",
        "18": "<p><strong>Makkeh nefesh behemah</strong> — killing an animal. <strong>Yeshallemenah nefesh tachat nefesh</strong>: 'he shall restore it — life for life.' The <em>nefesh tachat nefesh</em> formula applies here to animal restitution (monetary compensation, not execution), establishing that the same phrase can function at both capital (human) and property (animal) levels. The principle: equivalent compensation is owed; the nature of the victim determines the nature of the compensation.</p>",
        "19": "<p><strong>Mum be'amito ken ye'aseh lo</strong>: 'as he has done to his neighbor, so it shall be done to him.' The lex talionis formula — introduced here before its detailed enumeration in v. 20. This general statement of equivalent retribution is the principle underlying all the specific applications that follow. <em>Mum</em> (H3971): a blemish, defect, or disfigurement — the same word used for physical disqualification from the priesthood (Lev 21:17-23). The legal concept of <em>mum</em> maps from the sacrificial system to personal injury law.</p>",
        "20": "<p><strong>Shever tachat shever, 'ayin tachat 'ayin, shen tachat shen</strong>: 'fracture for fracture, eye for eye, tooth for tooth.' The lex talionis triad (also in Ex 21:24; Deut 19:21) is a principle of proportional justice, not a license for personal revenge. The formula limits punishment to the equivalent of the injury done — no more. In the ANE context, where wealthy offenders could simply pay fines and powerful ones could exact disproportionate retribution, the lex talionis was a leveling law: the punishment must fit the crime, regardless of relative social status.</p>",
        "21": "<p>The verse summarizes and connects both law categories: animal killing → restitution; human killing → execution. The juxtaposition (<em>behemah... adam</em>) makes the hierarchy explicit: human life carries capital weight; animal life carries restitution weight. The same <em>nefesh</em> term applies to both (both have life-essence), but the <em>tselem Elohim</em> of human beings uniquely grounds the capital response.</p>",
        "22": "<p><strong>Mishpat echad yihyeh lachem</strong>: 'You shall have one law for you.' <strong>Lager kaeezrach</strong>: for the <em>ger</em> (resident alien) and the <em>ezrach</em> (native-born) alike. The legal egalitarianism of the Mosaic code — one standard across social and ethnic categories — is a defining feature repeatedly insisted upon (cf. Ex 12:49; Num 15:16,29). The covenant community is not a tribal law-zone where insiders are protected differently from outsiders; the law's authority extends to all who dwell in YHWH's land.</p>",
        "23": "<p>The blasphemer is brought outside the camp and stoned — Moses and the Israelites <em>ka'asher tsivah YHWH et-Moshe</em> ('as YHWH commanded Moses'). The narrative closure formula emphasizes exact obedience to the divine ruling: no deviation, no mercy plea. The legal case serves as a paradigm for all subsequent blasphemy cases: the procedure established here is the normative precedent. The outside-the-camp execution removes the guilty person and the pollution of blasphemy from the covenant community.</p>"
    },
    "25": {
        "1": "<p><strong>Behar Sinai</strong>: 'on Mount Sinai' — the sabbatical and jubilee laws are explicitly anchored at Sinai. This geographical grounding is unusual for laws given in Leviticus (where the default setting is the tent of meeting). The Sinai reference underscores that the land-rest laws are not agricultural policy but covenant obligations carrying the same authority as the Ten Words. The opening of the Mishnah tractate <em>Avot</em> — 'Moses received Torah from Sinai' — cites this verse as its proof-text.</p>",
        "2": "<p><strong>Shabbat ha-aretz la-YHWH</strong>: 'the land shall have a sabbath to YHWH' — the land itself is the subject of sabbath observance, not merely its human inhabitants. <em>Shabbat</em> (H7676): cessation/rest. The land sabbath (<em>shemittah</em>) extends the seventh-day creation pattern (Gen 2:2-3) to the agricultural cycle: as YHWH rested from creation, the land rests from cultivation. The land belongs to YHWH (v. 23 <em>ki li ha-aretz</em>); its sabbath is owed to him, not chosen by the farmer.</p>",
        "3": "<p>Six years of active cultivation — sowing, pruning, gathering. The six-year agricultural cycle mirrors the six-day creation week, with the seventh given to YHWH. The enumeration of the three activities (<em>tizra... tizmor... asafta</em> = sow, prune, gather) covers the full range of agricultural labor. The positive description of productive labor in the six years sets up the contrast: not sloth but trust is demanded in the seventh.</p>",
        "4": "<p><strong>Shabbat shabbaton la-YHWH</strong> (<em>shabbat shabbaton</em>, H7676+H7677): 'a complete sabbath rest to YHWH' — the double noun formation is the superlative or intensive: an absolute, total rest. The same intensive form is used for Yom Kippur (Lev 16:31; 23:32). <strong>Shemittah</strong> (H8057): the sabbatical year; from <em>shamat</em> (H8058): to let drop, release, desist. <em>Shamat</em> is also used in Deut 15:1-3 for the remission of debts in the seventh year: the same release principle applies to both land and debt.</p>",
        "5": "<p><strong>Sephiach</strong> (H5599): the 'aftergrowth' — grain that grows spontaneously from seeds left from the previous harvest, without deliberate sowing. <strong>Karmekha ha-nazir</strong> (<em>nazir</em>, H5139 in agricultural sense): your 'unpruned vine' — the same root as the Nazirite (<em>nazir</em> = set apart/let grow unrestrained). In the sabbatical year the vine is left untended, 'set apart,' as the Nazirite lets his hair grow without cutting. The sabbatical year makes the land itself a kind of Nazirite — set apart from human management.</p>",
        "6": "<p><strong>Shabbat ha-aretz lachem leokhlah</strong>: 'the sabbath produce of the land shall be food for you.' The sabbatical year's spontaneous produce is not wasted — it becomes shared food: for the owner, male and female servants, hired workers (<em>sakir</em>), resident aliens (<em>toshav</em>), and strangers. The sabbatical year converts private agricultural yield into shared communal provision. The land owner relinquishes exclusive claim to the seventh year's produce; it belongs to all who dwell in the land.</p>",
        "7": "<p>The land's sabbatical produce also feeds the livestock (<em>behemtekha</em>) and the wild animals (<em>chayat ha-aretz</em>). The inclusion of wild animals is remarkable: the benefits of the sabbatical year extend beyond the covenant community to the non-domesticated creation. This ecological dimension of the sabbatical mirrors the Sabbath command in Ex 23:12 ('so that your ox and donkey may rest') and the Noahic covenant's breadth (Gen 9:10 — 'every living creature').</p>",
        "8": "<p><strong>Veasafta lekha sheva shabbetot shanim</strong>: 'You shall count for yourself seven sabbaths of years — seven times seven years.' The seven-times-seven counting produces forty-nine; the fiftieth year is the jubilee. The same arithmetic appears in the counting for Shavuot (Lev 23:15-16: seven sabbaths + one day = fifty). The jubilee's fifty-year cycle is the macro-scale counterpart to Pentecost's fifty-day cycle: both are completions beyond the perfect number seven, adding one to arrive at a new beginning.</p>",
        "9": "<p><strong>Bishvi'i bahodesh ha-asiri beyom ha-kippurim</strong>: on the tenth day of the seventh month — Yom Kippur — the <em>yovel</em> is inaugurated. The jubilee begins on the Day of Atonement, not on the new year: freedom (<em>deror</em>) is proclaimed after atonement is made. <strong>Veha'avarta shofar teru'ah</strong>: sound the shofar of great noise throughout all your land. The jubilee is announced by sound — not a written decree but a trumpet blast heard everywhere. The shofar (<em>qeren ha-yovel</em>, the ram's horn) is the instrument that gives the year its name.</p>",
        "10": "<p><strong>Yovel</strong> (H3104): 'jubilee' — likely from <em>yobel</em> (ram) referring to the ram's horn used to announce it, or possibly from a root meaning 'to carry/flow.' <strong>Deror</strong> (H1865): 'freedom, liberty, release' — a rare and powerful word (Isa 61:1 'to proclaim freedom to the captives' uses this exact term). The jubilee proclamation is: <em>veniqatem deror ba-aretz lekhol yosheveha</em> — 'you shall proclaim freedom throughout the land to all its inhabitants.' Every person returns to their ancestral property; every Israelite debt-slave goes free. The jubilee is the structural undoing of accumulated inequality.</p>",
        "11": "<p><strong>Yovel hi</strong>: 'it is the jubilee.' The fiftieth year is <em>qodesh</em> (holy) — set apart, like the Sabbath itself. No sowing, no reaping of aftergrowth, no harvesting of the untended vine. The jubilee year adds to the sabbatical year's prohibitions the dimension of universal return: it is not merely an agricultural rest but a social reset. The land's rest and the social reset happen simultaneously, bound together in the single concept of <em>yovel</em>.</p>",
        "12": "<p><strong>Me'asher ha-sadeh tochalenu</strong>: 'you may eat what it produces directly from the field.' The jubilee's produce is eaten directly (<em>al pi hasadeh</em>) without processing, storage, or commerce. The immediacy of eating from the field without economic mediation is a return to pre-agricultural intimacy with the land — reminiscent of the garden (Gen 2:9 'every tree that is pleasant to eat'). The jubilee year's food-access pattern reverses the post-Eden labor curse (Gen 3:17-19) at least temporarily.</p>",
        "13": "<p><strong>Bishnat ha-yovel ha-zo tashuvu ish el achuzato</strong>: 'In this jubilee year each of you shall return to his own property.' <em>Achuzah</em> (H272): ancestral property, the holding given by YHWH to each family at the original distribution of the land (Num 26-36; Josh 13-21). The return to the <em>achuzah</em> is not merely a property transfer but a restoration of the original covenant allocation: the jubilee resets the land back to YHWH's initial apportionment, undoing all subsequent alienations.</p>",
        "14": "<p><strong>Lo tonu ish et achiv</strong>: 'Do not oppress one another.' <em>Yanah</em> (H3238): to oppress, to deal wrongfully with, to take advantage of — a term particularly associated with economic exploitation. The land-sale law is reframed as an anti-oppression principle: any transaction involving land near the jubilee must account for the remaining years until restoration. Overcharging (many years left = high price; few years = low price) is the only legitimate pricing principle; to charge otherwise is economic oppression.</p>",
        "15": "<p><strong>Bemispar shanim acharei ha-yovel tiqneh me'et amitekha</strong>: purchase according to the number of years remaining after the jubilee. The jubilee transforms all land sales into time-limited leases: what is actually purchased is not the land but the harvests remaining until the next jubilee. The Hebrew economic concept is that YHWH's land cannot be permanently alienated — it belongs to him (v. 23) and returns to his original allocation at the jubilee. 'Selling land' is linguistically inaccurate in this system; you sell harvest rights.</p>",
        "16": "<p><strong>Lafi rov ha-shanim tarbeh mikhnato velafi mi'ut ha-shanim tamit mikhnato</strong>: 'according to more years increase the price; according to fewer years decrease it.' The variable pricing of land based on jubilee proximity is economically equivalent to a lease: a house rented for 20 years costs more than one rented for 5 years. The law forces this temporal accounting into every land transaction, preventing the pretense that land can be permanently sold and thereby permanently concentrated in wealthy hands.</p>",
        "17": "<p><strong>Lo tonu ish et amito veyareta me-Elohekha</strong>: 'Do not oppress one another, but fear your God.' The prohibition is grounded not in a contractual ethic but in <em>yir'at Elohim</em> (H3374+H430): the fear of God. <em>Yir'at Elohim</em> in Leviticus (here; 19:14,32; 25:36,43) is the consistent motivating ground for ethics that cannot be externally enforced: God sees what human courts cannot — inner intentions, covert overcharging, hidden coercion. The fear of God fills the gaps where human law has no reach.</p>",
        "18": "<p><strong>Va'asitem et chuqotai ve'et mishpatai tishmevu</strong>: 'Do my statutes and keep my rules.' The sabbatical/jubilee laws are part of the covenant obligations whose keeping brings <em>lavetach</em> (security) in the land. The conditional promise ('do this → live securely') embeds the land's wellbeing in covenant faithfulness. Sabbatical observance is not merely ecological rest but covenant trust: trusting YHWH to provide in the seventh year is the concrete test of whether the covenant relationship is functional.</p>",
        "19": "<p><strong>Venatna ha-aretz piryah</strong>: 'the land will give its fruit.' The responsive land — a personified agent in Leviticus's theology — yields or withholds according to the covenant's condition. Compare Lev 26:3-5 (obey → land yields) and 26:20 (disobey → land withholds). The land itself is embedded in the covenant as a responsive party: it is YHWH's land (v. 23), and it responds to whether YHWH's laws are kept on it.</p>",
        "20": "<p><strong>Vekhi tomervu</strong>: 'And if you ask' — the anticipated objection to the sabbatical year. The question 'what will we eat in the seventh year if we do not sow or gather?' is the practical test of faith: the sabbatical year asks for a full year of agricultural trust in YHWH's provision. The law anticipates the objection (as it anticipates the Passover question in Ex 12:26 and the son's question in Deut 6:20) — the system is designed to generate the question so that the answer can teach.</p>",
        "21": "<p><strong>Vetziviti et birkati lachem bashanah hashishit</strong>: 'I will command my blessing on you in the sixth year.' YHWH's advance provision for the sabbatical year: a triple yield in the sixth year that carries through the seventh and eighth until the ninth year's harvest arrives. The provision is not natural agricultural abundance but divinely commanded blessing (<em>birkati</em>). The sabbatical system requires a prior act of divine generosity that makes the seventh-year trust feasible; the law does not demand trust without providing the means.</p>",
        "22": "<p>The precise arithmetic of the provision: the sixth year's crop feeds from the eighth year's sowing until the ninth year's harvest. The triple-yield provision spans three calendar years, bridging the gap created by the sabbatical year's non-sowing. The specificity of the timeline (sixth → seventh → eighth → ninth) shows that the sabbatical system was designed with awareness of the agricultural calendar's gaps and was guaranteed adequate provision at each transition.</p>",
        "23": "<p><strong>Veha-aretz lo timmakher litsmitut ki li ha-aretz</strong>: 'The land shall not be sold permanently, for the land is mine.' This is the theological ground of the entire jubilee system: <strong>ki li ha-aretz</strong> — YHWH's ownership claim on the land of Canaan is absolute and permanent. <strong>Ki gerim vetoshavim atem imadi</strong>: 'you are but aliens and sojourners with me.' Israel's tenure in the land is as resident aliens with YHWH as the true landowner — the identical status Israel held in Egypt (<em>gerim</em> = resident aliens), now applied to their relationship to YHWH in their own land.</p>",
        "24": "<p><strong>Uge'ulah titenu la-aretz</strong>: 'you shall provide redemption for the land' throughout all the land you hold as a possession. <em>Ge'ulah</em> (H1353): redemption — from <em>ga'al</em> (H1350, the kinsman-redeemer verb). The right of redemption is embedded in every land transaction from the outset: no land sale in Israel is final, because redemption rights are permanently attached to every piece of land. The law does not merely permit redemption but requires that its possibility be built into every transaction.</p>",
        "25": "<p><strong>Im dash achikha</strong>: 'if your brother becomes poor.' The poor Israelite is consistently addressed as <em>ach</em> (brother) in ch. 25 (vv. 25,35,36,39,47) — a relational vocabulary that frames poverty relief as a family obligation. <strong>Go'alo ha-qarov elav</strong> (<em>go'el</em>, H1350): 'his nearest kinsman-redeemer.' The <em>go'el</em> is the closest male relative who has the right (and obligation) to restore lost property, redeem a debt-slave relative, and avenge blood. The institution of the <em>go'el</em> is one of the most theologically loaded in the OT: YHWH himself is described as Israel's <em>go'el</em> (Isa 41:14; 44:6; Job 19:25).</p>",
        "26": "<p><strong>Ve'ish ki lo yihyeh lo go'el</strong>: 'If a man has no one to redeem for him' — the case of the man without a kinsman-redeemer available. The law provides a fallback: self-redemption if the original seller becomes financially capable. The progressive cascade of options (go'el first; then self-redemption; then jubilee) ensures that alienated property returns to its original family eventually — the jubilee is the absolute backstop when all other redemption mechanisms fail.</p>",
        "27": "<p><strong>Vichishav et shne mimkaro</strong>: calculation of years since the sale to determine the refund amount. The sell-back price is the purchase price minus the value of years already used — the elapsed harvests are deducted. This actuarial calculation at every potential redemption point requires that the original sale price be documented and remembered. The redemption system demands financial transparency and precise accounting across potentially decades.</p>",
        "28": "<p>If the seller cannot afford to buy back, the property remains with the buyer until the jubilee (<em>yovel</em>), when it goes out free — <strong>veyatsa bayovel</strong>. The jubilee serves as the ultimate economic reset mechanism: what human poverty and failed redemption could not restore, the jubilee automatically restores. The fiftieth year is the covenant's structural guarantee that no Israelite family loses its land permanently regardless of economic misfortune.</p>",
        "29": "<p><strong>Ish ki yimkor beit moshav ir chomah</strong>: 'if a man sells a dwelling house in a walled city.' The urban exception: houses in walled cities have a one-year redemption window after which the sale becomes permanent (v. 30). The walled-city exception distinguishes between agricultural land (which embeds tribal covenant identity and cannot be permanently alienated) and urban real estate (which is more fungible). The jubilee system protects the covenant foundation — ancestral agricultural land — more strongly than urban property.</p>",
        "30": "<p>If the house is not redeemed within the calendar year, <strong>lo yetse bayovel</strong>: it does not go out in the jubilee — it remains permanently with the buyer. The walled-city exception from jubilee release reflects a recognition that urban property markets function differently from tribal land tenure. The permanent sale of urban housing is permitted because such houses are not part of the covenant land-distribution that the jubilee is designed to protect.</p>",
        "31": "<p><strong>Batei ha-chatzerim</strong>: 'houses of the open villages' (without surrounding walls). These are treated like open-field land (<em>al sadeh ha-aretz yechashev</em>) — redeemable at any time and released in the jubilee. The village/walled-city distinction is a legal category based on defensibility and market integration: villages function economically as extensions of the agricultural land system; walled cities participate in trade networks with different alienation patterns.</p>",
        "32": "<p><strong>Arei ha-Leviyim</strong>: the Levitical cities. The Levites received no ancestral land-share (Num 18:20-24; Josh 13:14) — their possession within Israel is the 48 designated cities. Their houses in those cities carry permanent redemption rights: a Levite can always buy back a sold house, and the houses in Levitical cities always return in the jubilee. The Levites' unique land-status (no tribal territory; only city allotments) requires special jubilee provisions to protect their right to their only fixed possession.</p>",
        "33": "<p>Even if a Levite's house is purchased by a non-Levite, it returns in the jubilee because the Levitical cities are <strong>achuztam betokh bne Yisrael</strong>: 'their possession among the Israelites.' The jubilee's return mechanism ensures that the Levitical city allotments remain in Levitical tenure permanently — the cities that serve as YHWH's mediators' bases cannot be permanently absorbed into tribal territories.</p>",
        "34": "<p><strong>Uve'migrash areichem lo yimmakher</strong>: 'the open land around their cities may not be sold at all.' The <em>migrash</em> (H4054): the pastureland surrounding Levitical cities (Num 35:1-8) — its size was specifically specified in the original land allocation. This pastureland is categorically excluded from the sale system entirely: not merely subject to redemption and jubilee, but unsaleable in any year. The Levites' grazing land is permanently YHWH's provision for his servants.</p>",
        "35": "<p><strong>Im dash achikha umata yado imakh</strong>: 'If your brother becomes poor and his hand falters beside you.' <strong>Vehechezaqta bo</strong>: 'you shall support him' — the verb <em>chazaq</em> (H2388) means to strengthen, to hold firm, to grasp. The poor Israelite's hand 'faltering' (<em>mutt</em> = slipping, tottering) is met by the community's holding hand. The imagery is physical: one person's grip weakens; another grabs it. <strong>Ger vetoshav</strong>: even resident aliens qualify for this support — the solidarity extends across ethnic categories within the covenant community.</p>",
        "36": "<p><strong>Al tiqqach me'itto neshekh vetarbith</strong>: 'do not take interest or profit from him.' <strong>Neshekh</strong> (H5392): interest — from <em>nashakh</em> (H5391): 'to bite.' The image of interest as biting suggests predatory extraction: each payment-period the debt 'bites' the debtor more. <strong>Tarbith</strong> (H8635): increase, profit — from <em>rabah</em> = to multiply. The pairing of <em>neshekh</em> (interest on money) and <em>tarbith</em> (profit on goods) covers all forms of lending-for-gain to the poor brother. <strong>Veyareta me-Elohekha</strong>: fear your God — YHWH sees the exploitative lending that courts cannot detect.</p>",
        "37": "<p><strong>Et kasphekha lo titen lo beneshekh vebemarkheit lo titen lo letarbith</strong>: no interest on money, no profit on food. The dual prohibition — money-lending and food-lending — covers the two most basic resources: liquidity and subsistence. Lending food at profit to a starving neighbor extracts maximum value from their desperation. The prohibition names both because both would occur in practice. Deuteronomy 23:19-20 extends the prohibition to any kind of loan to a fellow Israelite while permitting it with foreigners.</p>",
        "38": "<p><strong>Ani YHWH Eloheikhem asher hotzeti etchem me'eretz Mitzrayim</strong>: 'I am YHWH your God who brought you out of the land of Egypt.' The Exodus-grounding formula provides the theological foundation for the interest prohibition: YHWH rescued Israel from economic exploitation (Egyptian slave labor); to exploit a poor fellow-Israelite with predatory lending contradicts the community's founding experience. The character of YHWH as liberator grounds all obligations to the economically vulnerable.</p>",
        "39": "<p><strong>Ve'im dash achikha imakh umikhar lakh</strong>: 'If your brother becomes poor and sells himself to you' — debt slavery as the extreme of poverty: the person himself becomes the collateral. <strong>Lo ta'avod bo avodat eved</strong>: 'do not make him work as a slave.' The Israelite debt-laborer must not be treated as a <em>chatsi</em> (permanent property-slave) but as a <em>sakir vetoshav</em> (a hired worker and resident alien). The distinction is categorical: same labor; different relationship; different dignity.</p>",
        "40": "<p><strong>Keshakir ketoshav yihyeh imakh</strong>: 'He shall be with you as a hired worker and a resident alien.' The hired worker (<em>sakir</em>, H7916) and resident alien (<em>toshav</em>, H8453) are free persons who work for wages or lease arrangements — not slaves. The Israelite debt-laborer retains the legal personhood of a free contractor even while working off a debt. <strong>'Ad shenat ha-yovel</strong>: his service ends at the jubilee — the outermost limit of any Israelite's bonded labor.</p>",
        "41": "<p><strong>Veyatsa me'immakh hu uvanov</strong>: 'He goes free from you — he and his children with him.' The jubilee release includes the debt-laborer's children: the family unit is freed together. The family-inclusive release prevents the perpetuation of servitude into the next generation — children born into debt-service are not thereby born into permanent servitude. <strong>Veshav el mishpachto</strong>: return to his family; <strong>vel'achuzat avotav</strong>: and to his ancestral property. The jubilee restores three things: freedom, family, and land.</p>",
        "42": "<p><strong>Ki avadai hem asher hotzeti otam me'eretz Mitzrayim</strong>: 'For they are my servants, whom I brought out of the land of Egypt.' YHWH's prior claim on every Israelite prevents any other person's permanent ownership of them. The Exodus is the theological ground for the Israelite's inalienable freedom: having been liberated by YHWH, no Israelite can be permanently enslaved to a human master. <strong>Lo yimmakeru mimkarat eved</strong>: 'they shall not be sold as slaves' — the sale of a human being as permanent property is prohibited for any Israelite.</p>",
        "43": "<p><strong>Lo tirdeh vo befarekh</strong>: 'You shall not rule over him with ruthlessness.' <strong>Parekhk</strong> (H6531): crushing/crushing labor — the same word used for Egypt's treatment of Israel in Ex 1:13-14 ('they made the Israelites work with <em>parekhk</em>'). The term is a loaded one: to treat an Israelite debt-laborer with <em>parekhk</em> is to become Pharaoh. The Exodus narrative is the implicit reference text for every labor-relations law in Leviticus 25; the memory of Egyptian oppression is the standard against which all Israelite master-servant relations are measured.</p>",
        "44": "<p><strong>Ve'avdekha va'amatekha asher yihyu lakh</strong>: foreign slaves may be acquired from surrounding nations. The distinction between permanent foreign slavery (permitted) and permanent Israelite debt-service (prohibited) reflects the covenant community's unique status rather than a universal social ethics. The jubilee system is specifically a covenant institution for the covenant people — it does not purport to be a global economic program. The Mosaic law's protections are strongest for those within the covenant community and progressively weaker for those further outside it.</p>",
        "45": "<p><strong>Uvetemishpachot ha-ger ha-toshav</strong>: and from the children of the resident aliens who sojourn among you — the second generation of resident aliens is also eligible for permanent purchase. <em>Ger toshav</em> (H1616+H8453): the resident alien — a person dwelling permanently within Israel without the full covenant status of a native Israelite. The graduated system of persons (native Israelite / resident alien / foreign sojourner / outside national) maps onto graduated degrees of economic protection.</p>",
        "46": "<p><strong>Vehitnahaltem otam livneikhem</strong>: 'You may bequeath them to your children as an inheritance.' Foreign slaves may be passed through inheritance as permanent property, unlike Israelite debt-laborers who go free at jubilee. <strong>Va'acheikhem bne Yisrael lo yirdeh ish be'achiv befarekh</strong>: 'but over your brothers, the Israelites, you shall not rule harshly' — the <em>parekhk</em> prohibition applies categorically to Israelite-on-Israelite relations. The verse thus establishes a two-tier system: permanent servitude for foreign slaves; limited, humanely constrained labor for Israelites.</p>",
        "47": "<p><strong>Ve'im tasig yad ger vetoshav imakh</strong>: if the resident alien grows rich while the Israelite beside him becomes poor, and the Israelite sells himself to the resident alien. The scenario is socially inverted from the norm: the native becomes the alien's dependent. Even in this unusual situation the same redemption rights (<em>ge'ulah</em>) apply: the Israelite's kinsmen may redeem him, and the jubilee remains the ultimate backstop.</p>",
        "48": "<p><strong>Acharei nimmakhar ge'ulah tihyeh lo</strong>: 'after he is sold he retains the right of redemption.' The right of redemption is not forfeited by the act of selling oneself — it is a permanent, inalienable legal right attached to every Israelite's person. <em>Ge'ulah</em> (H1353): the right and obligation of kinship-redemption. Even the most desperate economic act (self-sale) does not extinguish the kinship-solidarity mechanism.</p>",
        "49": "<p><strong>Dodo o ven-dodo yig'alenu</strong>: his uncle or uncle's son may redeem him; or any close relative from his family (<em>mishpachto</em>) may redeem him. The kinship network of redemption expands outward through the family tree: brother → uncle → cousin → more distant relative → self-redemption. The graduated kinship cascade ensures that the redemption obligation falls on the closest available relative first, maximizing the chance that redemption actually occurs before the jubilee. The theology of the <em>go'el</em> as the one who comes to the aid of a helpless relative is one of the OT's richest: Ruth 4 (Boaz as <em>go'el</em>), Job 19:25 (YHWH as <em>go'el</em>).</p>",
        "50": "<p><strong>Vichishav im qoneihu</strong>: 'he shall reckon with his buyer' — a financial calculation from the year of sale to the jubilee. The self-sale price is divided by the years of service, and the remaining years' value is the redemption price. The actuarial precision required maintains financial fairness in both directions: the buyer is not defrauded by early redemption; the seller's family is not gouged by an excessive buyout price. The law creates a formula rather than leaving redemption to negotiation.</p>",
        "51": "<p><strong>Im od rabbot bashanim</strong>: if many years remain, the redemption payment is proportionally larger — 'from the money of his purchase he shall refund a proportionate portion as redemption.' The graduated redemption price (<em>lafi shanim</em> = according to years) treats the original purchase as a future-labor annuity. Each year of service is worth one fraction of the total; years already worked are paid off; years remaining are what the buyer loses through redemption. The formula is transparent and calculable.</p>",
        "52": "<p><strong>Ve'im me'at nish'ar bishnot</strong>: if few years remain until the jubilee, the calculation produces a small redemption payment. The asymmetric redemption pricing (large early, small late) creates an economic incentive for the family to redeem early when the cost is high: the longer they wait, the less they pay — but also the fewer years their kinsman is freed early. The system incentivizes early redemption without making late redemption prohibitively expensive.</p>",
        "53": "<p><strong>Keshkir shanah beshanah yihyeh imo</strong>: 'he shall be with him as a worker hired year by year.' The Israelite self-sold to a foreigner retains the legal status of an annual contract worker — not a permanent slave. <strong>Lo yirdenu befarekh le'einekha</strong>: 'he shall not rule over him harshly in your sight.' The Israelite community is charged with oversight (<em>le'einekha</em> = in your eyes/sight) of how a kinsman in foreign service is treated. Social accountability extends to monitoring the treatment of Israelites working for resident aliens.</p>",
        "54": "<p><strong>Ve'im lo yiggal be'eleh</strong>: 'if he is not redeemed in any of these ways, he goes free in the year of jubilee — he and his children with him.' The jubilee is the absolute floor: regardless of the failure of all redemption mechanisms, the jubilee releases every Israelite from bonded service. The jubilee cannot be contracted away: no agreement between buyer and seller can override it. It is YHWH's structural guarantee for every Israelite, operative regardless of any human transaction.</p>",
        "55": "<p><strong>Ki li bene Yisrael avadim avadai hem asher hotzeti otam me'eretz Mitzrayim</strong>: 'For to me the Israelites are servants; they are my servants whom I brought out of the land of Egypt: I am YHWH your God.' The chapter closes with the Exodus-ownership declaration. The jubilee system's entire logic rests on this foundation: YHWH owns every Israelite because he liberated them from Egypt. His ownership right on them is prior to and stronger than any human economic claim. The jubilee is not social generosity but YHWH's reclamation of what has always been his.</p>"
    }
}

def main():
    data = load_comm('mkt-original', 'leviticus')
    merge_comm(data, LEVITICUS)
    save_comm('mkt-original', 'leviticus', data)

    import json as _json, pathlib as _p
    ROOT2 = _p.Path(__file__).parent.parent
    out = _json.loads((ROOT2 / 'data/commentary/mkt-original/leviticus.json').read_text())
    il  = _json.loads((ROOT2 / 'data/interlinear/leviticus.json').read_text())
    all_ok = True
    for ch in range(24, 26):
        ck = str(ch)
        missing = set(il.get(ck, {}).keys()) - set(out.get(ck, {}).keys())
        if missing:
            print(f'ch {ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'ch {ch}: complete ({len(out.get(ck, {}))} verses)')
    if all_ok:
        print('All verses present')

if __name__ == '__main__':
    main()
